sql:
SELECT city_name, province_id
FROM cities
WHERE province_id = (SELECT province_id FROM provinces WHERE province_name = 'Caloocan City');

SELECT facilities.actual_name, addresses.mapping_address
FROM facilities
INNER JOIN addresses ON facilities.address_id = addresses.address_id;

external_knowledge:
- "Heart of NCR" and "shadow of Cagayan Valley" metaphorically refer to facilities located in the region NCR but belonging to the province Cagayan Valley;
- "Gleaming reputation" metaphorically refers to facilities with high average rating scores;
- "Above the threshold of mediocrity" metaphorically suggests an average rating score greater than 4.

- 'places' refers to facilities;
- 'reviewed at least three times' means the number of reviews is 3 or more;
- 'over the past year' indicates the reviews should be from the last year.
